urlset:
{% for page in site.pages %}
{% if page.url != "/404.html" and page.url != "/robots.txt" and page.url != "/sitemap.xml" and page.url != "/feed.xml" %}

  {{ site.url }}{{ site.baseurl }}{{ page.url }}
  {% if page.date %}{{ page.date | date_to_xmlschema }}{% else %}{{ site.time | date_to_xmlschema }}{% endif %}
  monthly
  0.8

{% endif %}
{% endfor %}
